const express = require('express');
const router = express.Router();

router.get('/auth/callback', (req, res) => {
  const returnUrl = req.query.return_url;
  
  // Validate return URL to prevent open redirects
  if (!returnUrl || typeof returnUrl !== 'string') {
    return res.status(400).send('Invalid return URL');
  }
  
  // Basic validation to prevent open redirects
  try {
    const url = new URL(returnUrl, process.env.APP_URL || 'http://localhost:3000');
    const allowedHosts = [new URL(process.env.APP_URL || 'http://localhost:3000').host];
    
    if (!allowedHosts.includes(url.host)) {
      return res.status(400).send('Invalid return URL host');
    }
  } catch (error) {
    return res.status(400).send('Invalid return URL format');
  }
  
  // Here you would typically handle the OAuth callback
  // and extract user information from the authentication provider
  
  // For demonstration, we'll assume authentication was successful
  // and redirect to the return URL
  res.redirect(returnUrl);
});

module.exports = router;